PROC BOXPLOT &lt;ANNOTATE=SAS-data-set&gt;&lt;BOX=SAS-data-set&gt;&lt;DATA=SAS-data-set&gt;&lt;GOUT=&lt;libref.&gt;output catalog&gt;&lt;HISTORY=SAS-data-set&gt;;     
	BY &lt;DESCENDING&gt;&lt;NOTSORTED&gt; ;

	ID variable(s) ;

	INSET &lt;CFILL=color | BLANK&gt;&lt;CFILL=BLANK&gt;&lt;CFILLH=color&gt; ...;

	INSETGROUP &lt;CFILL=color | BLANK&gt;&lt;CFILL=BLANK&gt;&lt;CFILLH=color&gt; ...;

	PLOT &lt;ALLLABEL=&lt;VALUE | (variable)&gt;&gt;&lt;ANNOTATE=SAS-data-set&gt;&lt;BLOCKLABTYPE=&lt;SCALED | TRUNCATED&gt;&gt; ...;
